//! 第 5 步最小 Linux syscall 分发层。
//!
//! 这一层负责两件事：
//! 1. 从 trap frame 抽出 Linux syscall 号与参数，形成显式的
//!    `LinuxSyscallInvocation`；
//! 2. 把最小文件、目录、fd、时间和进程语义集中到单点分发，未实现 syscall
//!    稳定返回 `ENOSYS`。
//!
//! 当前仍然只服务“最小 bring-up + 单线程 exec 替换”这一窄路径，不引入完整进程组、
//! 命名空间或通用 VFS fd 语义。

use crate::arch::{ArchSyscallAbi, decode_syscall_abi};
use crate::task::{CurrentThread, Thread};
use axerrno::{LinuxError, LinuxResult};
use axhal::context::TrapFrame;
use core::time::Duration;

mod compat;
pub(crate) mod fdprobe;
mod fs;
mod futex;
mod io;
mod memory;
pub(crate) mod net;
mod poll;
mod process;
mod signal;
mod thread;
mod time;

pub(crate) use fs::{release_advisory_locks_for_cloexec_close, release_advisory_locks_for_process};
pub(crate) use memory::detach_all_sysv_segments;
pub(crate) use signal::RT_SIGRETURN_SYSCALL;

const SIGKILL: i32 = 9;
const SIGSYS: i32 = 31;
const SECCOMP_MODE_DISABLED: usize = 0;
const SECCOMP_MODE_STRICT: usize = 1;
const SECCOMP_MODE_FILTER: usize = 2;

/// 一次允许被 signal 提前打断的阻塞 syscall 等待窗口。
#[derive(Clone, Copy, Debug)]
pub(super) struct InterruptibleBlock {
    deadline: Option<Duration>,
}

impl InterruptibleBlock {
    pub(super) const fn new(deadline: Option<Duration>) -> Self {
        Self { deadline }
    }
}

/// 阻塞 syscall 被 signal 打断后暴露给用户态的最小返回形状。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(super) enum InterruptedSyscallResult {
    Eintr,
}

impl InterruptedSyscallResult {
    pub(super) const fn into_linux_error(self) -> LinuxError {
        match self {
            Self::Eintr => LinuxError::EINTR,
        }
    }
}

/// deadline 等待中一次“完成 / 超时 / 被 signal 打断”的共享等待结果。
#[derive(Debug)]
pub(super) enum SignalAwareDeadlineWait<T> {
    Complete(T),
    TimedOut,
    Interrupted(InterruptedSyscallResult),
}

pub(super) fn wait_with_signal_deadline<T>(
    current: &Thread,
    block: InterruptibleBlock,
    mut try_complete: impl FnMut() -> Result<Option<T>, LinuxError>,
    mut on_idle: impl FnMut(),
) -> Result<SignalAwareDeadlineWait<T>, LinuxError> {
    loop {
        if crate::task::should_interrupt_interruptible_block(current) {
            return Ok(SignalAwareDeadlineWait::Interrupted(
                InterruptedSyscallResult::Eintr,
            ));
        }
        if let Some(result) = try_complete()? {
            return Ok(SignalAwareDeadlineWait::Complete(result));
        }
        if block
            .deadline
            .is_some_and(|deadline| axhal::time::wall_time() >= deadline)
        {
            return Ok(SignalAwareDeadlineWait::TimedOut);
        }
        on_idle();
    }
}

/// Linux RISC-V `epoll_create1(2)` syscall 号。
const EPOLL_CREATE1_SYSCALL: usize = 20;
/// Linux RISC-V `epoll_ctl(2)` syscall 号。
const EPOLL_CTL_SYSCALL: usize = 21;
/// Linux RISC-V `accept(2)` syscall 号。
const ACCEPT_SYSCALL: usize = 202;
/// Linux RISC-V `accept4(2)` syscall 号。
const ACCEPT4_SYSCALL: usize = 242;
/// VOS 私有 RV64 musl `pathconf(3)` shim 入口；只由内存中补丁后的官方 musl libc 调用。
#[cfg(target_arch = "riscv64")]
const VOS_MUSL_PATHCONF_SYSCALL: usize = usize::MAX - 30;
/// VOS 私有 musl `gethostname(3)` shim 入口；只由内存中补丁后的官方 musl libc 调用。
#[cfg(any(target_arch = "riscv64", target_arch = "loongarch64"))]
