    let allocator = axalloc::global_allocator();
    AllocatorWatermark {
        available_pages: allocator.available_pages(),
        used_pages: allocator.used_pages(),
        available_bytes: allocator.available_bytes(),
        used_bytes: allocator.used_bytes(),
    }
}

