/// 注册 Linux syscall trap 处理器。
///
/// trap 层只做最薄的事情：
/// - 从 trap frame 抽出 syscall 号和参数；
/// - 取走当前运行中的 `Thread` 所有权并交给分发器；
/// - 把 `LinuxResult` 转成 Linux 约定的返回值寄存器。
#[register_trap_handler(SYSCALL)]
fn handle_minimal_syscall(tf: &TrapFrame, syscall_nr: usize) -> isize {
    let abi = decode_syscall_abi(tf);
    debug_assert_eq!(abi.nr, syscall_nr);
    let call = LinuxSyscallInvocation::from_abi(abi);
    let mut current = CurrentThread::take().expect("current thread is not initialized");
    current.set_last_syscall_nr(call.nr);
    trace_mmapstress_next_syscall_trap(
        &current,
        call.nr,
        crate::arch::next_syscall_ip(tf).saturating_sub(4),
    );
    trace_mmapstress_post_wait_child_syscall_trap(
        &current,
        call.nr,
        crate::arch::next_syscall_ip(tf).saturating_sub(4),
    );
    let trap_stack_top = user_trap_stack_top();
    match dispatch_minimal_syscall(current, tf, trap_stack_top, call) {
        Ok(ret) => resume_syscall_thread(tf, trap_stack_top, call.nr, ret as isize),
        Err(err) => resume_syscall_thread(tf, trap_stack_top, call.nr, -(err.code() as isize)),
    }
}

/// 注册用户态 page fault 处理器。
///
/// 语义分成两支：
/// - 内核态 fault 保持现有边界，返回 `false` 交给架构 trap glue 原样 panic；
/// - 用户态 fault 先尝试让当前地址空间修复；若失败，则重新安装当前线程并返回
///   `false`，交给带 `TrapFrame` 的 user-exception 通道投递可捕获 `SIGSEGV`。
#[register_trap_handler(PAGE_FAULT)]
fn handle_user_page_fault(vaddr: VirtAddr, access_flags: PageFaultFlags, is_user: bool) -> bool {
    if !is_user {
        return false;
    }

    let current = CurrentThread::take().expect("current thread is not initialized");
    trace_mmapstress_post_wait_child_page_fault(&current, vaddr.as_usize(), 0);
    assert_rv_mmapstress_kernel_sections(&current, "user-page-fault-before-growdown");
    if current.handle_growdown_page_fault(vaddr, access_flags) {
        assert_rv_mmapstress_kernel_sections(&current, "user-page-fault-after-growdown");
        axhal::asm::flush_tlb(Some(vaddr));
        poll_interruptible_timeouts();
        poll_futex_timeouts();
        if (take_interruptible_block_resched_pending() || take_futex_timeout_resched_pending())
            && has_ready_threads()
        {
            enqueue_runnable_deferred(current);
            unsafe { schedule_next_ready(user_trap_stack_top()) }
        }
        CurrentThread::install(current);
        return true;
    }
    assert_rv_mmapstress_kernel_sections(&current, "user-page-fault-before-handle");
    if current.with_aspace(|aspace| aspace.handle_page_fault(vaddr, access_flags)) {
        assert_rv_mmapstress_kernel_sections(&current, "user-page-fault-after-handle");
        current.mark_user_present_range(vaddr.as_usize(), 1);
        axhal::asm::flush_tlb(Some(vaddr));
        poll_interruptible_timeouts();
        poll_futex_timeouts();
        if (take_interruptible_block_resched_pending() || take_futex_timeout_resched_pending())
            && has_ready_threads()
        {
            enqueue_runnable_deferred(current);
            unsafe { schedule_next_ready(user_trap_stack_top()) }
        }
        CurrentThread::install(current);
        return true;
    }

    println!(
        "task: user page fault unresolved pid={}, tid={}, addr={:#x}, access={:?}",
        current.pid(),
        current.tid(),
        vaddr.as_usize(),
        access_flags
    );
    CurrentThread::install(current);
    false
}

