//! 用户态 trap 栈与最薄的进入 glue。
//!
//! 第 1 步微重构后，`kernel/src/user.rs` 不再承载完整 ELF/exec pipeline，而是只保留：
//! 1. 当前 RISC-V 用户态 trap 的独立内核栈；
//! 2. 进入用户态前计算 trap 栈顶地址的最小 glue。
//!
//! 真正的 ELF 解析、段装载与用户映像构造已经收拢到 `kernel/src/exec/`，为后续
//! `execve/argv/envp/auxv/PT_INTERP` 扩展腾出独立子系统位置。

use memory_addr::{VirtAddr, va};
#[cfg(target_arch = "riscv64")]
use core::sync::atomic::{AtomicBool, Ordering};

/// Linux RISC-V `exit` syscall 号。
pub const EXIT_SYSCALL: usize = 93;

/// Linux RISC-V `exit_group` syscall 号。
pub const EXIT_GROUP_SYSCALL: usize = 94;

/// 当前每个用户态 trap 使用的独立内核栈大小。
const USER_TRAP_STACK_SIZE: usize = 64 * 1024;
/// 栈底预留隔离区，避免轻微越界时直接覆盖相邻静态全局对象。
const USER_TRAP_STACK_GUARD_SIZE: usize = 16 * 1024;
/// 栈底剩余空间低于该阈值时直接 fail-fast，避免继续污染相邻静态对象。
///
/// 这个阈值只做早期告警，不应和静态 guard 大小绑死；当前评测里个别高压路径会把
/// trap stack 压到 16 KiB 以下但仍然安全，因此这里保留更宽的余量。
#[cfg(target_arch = "riscv64")]
const KERNEL_STACK_MIN_FREE: usize = 8 * 1024;
/// 栈指针刚越过已知栈底时仍立即诊断；更远处可能是其它合法任务栈。
#[cfg(target_arch = "riscv64")]
const KERNEL_STACK_UNDERFLOW_WINDOW: usize = 64 * 1024;
#[cfg(target_arch = "riscv64")]
static KERNEL_STACK_MARGIN_LOGGED: AtomicBool = AtomicBool::new(false);

#[allow(dead_code)]
#[repr(C, align(16))]
/// 带 16 字节对齐保证的 trap 栈物理载体。
struct TrapStack {
    guard: [u8; USER_TRAP_STACK_GUARD_SIZE],
    stack: [u8; USER_TRAP_STACK_SIZE],
}

/// 单核 bring-up 阶段唯一的用户态 trap 内核栈实例。
static mut USER_TRAP_STACK: TrapStack = TrapStack {
    guard: [0; USER_TRAP_STACK_GUARD_SIZE],
    stack: [0; USER_TRAP_STACK_SIZE],
};

/// 返回用户态 trap 使用的独立内核栈顶。
///
/// trap 入口仍沿用这块固定栈，保证当前第 1 步目录重组只搬执行链代码，不改变
/// 用户态 trap 的底层进入约定。
pub fn user_trap_stack_top() -> VirtAddr {
    // `stack` 保存静态 trap 栈底地址，后续与固定大小相加得到栈顶。
    let stack = unsafe { core::ptr::addr_of!(USER_TRAP_STACK.stack) };
    va!((stack as usize) + USER_TRAP_STACK_SIZE)
}

#[cfg(target_arch = "riscv64")]
fn user_trap_stack_bounds() -> (usize, usize) {
    let stack = unsafe { core::ptr::addr_of!(USER_TRAP_STACK.stack) } as usize;
    (stack, stack + USER_TRAP_STACK_SIZE)
}

#[cfg(target_arch = "riscv64")]
fn current_stack_pointer() -> usize {
    let sp: usize;
    unsafe {
        core::arch::asm!(
            "mv {sp}, sp",
            sp = out(reg) sp,
            options(nomem, nostack, preserves_flags)
        );
    }
    sp
}

#[cfg(target_arch = "riscv64")]
unsafe extern "C" {
    fn boot_stack();
    fn boot_stack_top();
}

#[cfg(target_arch = "riscv64")]
fn boot_stack_bounds() -> (usize, usize) {
    (boot_stack as usize, boot_stack_top as usize)
}

#[cfg(target_arch = "riscv64")]
fn assert_stack_margin(name: &str, sp: usize, low: usize, high: usize, context: &str) {
    let free = sp - low;
    if free < KERNEL_STACK_MIN_FREE {
        if !KERNEL_STACK_MARGIN_LOGGED.swap(true, Ordering::Relaxed) {
            println!(
                "kernel stack margin low in {context}: stack={name}, sp={sp:#x}, low={low:#x}, high={high:#x}, free={free:#x}"
            );
        }
    }
}

/// 在高压调度/清理路径上检查当前内核栈没有贴近静态对象边界。
#[cfg(target_arch = "riscv64")]
pub(crate) fn assert_kernel_stack_margin(context: &str) {
    let sp = current_stack_pointer();
    let (trap_low, trap_high) = user_trap_stack_bounds();
    let (boot_low, boot_high) = boot_stack_bounds();

    if sp >= trap_low && sp <= trap_high {
        assert_stack_margin("user_trap", sp, trap_low, trap_high, context);
        return;
    }

    if sp >= boot_low && sp <= boot_high {
        assert_stack_margin("boot", sp, boot_low, boot_high, context);
        return;
    }

    if sp < boot_low {
        let underflow = boot_low - sp;
        if underflow <= KERNEL_STACK_UNDERFLOW_WINDOW {
            panic!(
                "kernel stack underflow in {context}: stack=boot, sp={sp:#x}, low={boot_low:#x}, high={boot_high:#x}, underflow={underflow:#x}"
            );
        }
        return;
    }

    if sp > boot_high && sp < trap_low {
        let underflow = trap_low - sp;
        if underflow <= KERNEL_STACK_UNDERFLOW_WINDOW {
            panic!(
                "kernel stack underflow in {context}: stack=user_trap, sp={sp:#x}, low={trap_low:#x}, high={trap_high:#x}, underflow={underflow:#x}"
            );
        }
    }
    let _ = context;
}

#[cfg(not(target_arch = "riscv64"))]
pub(crate) fn assert_kernel_stack_margin(_context: &str) {}

